sql:
SELECT cash_amount
FROM dividend_events
WHERE cash_amount > 0;

SELECT COUNT(dividend_id) AS number_of_approved_dividends
FROM dividend_approvals
WHERE approval_date >= '2021-01-01';

SELECT cash_amount
FROM dividend_events
WHERE dividend_id = 1;

SELECT MAX(tax_amount) AS max_tax_amount
FROM tax_implications
WHERE dividend_id = 1;

SELECT effective_date
FROM regulatory_requirements
WHERE regulatory_body = 'SEC';

SELECT shareholder_id
FROM tax_implications
WHERE tax_filing_status = 'single' AND dividend_id = 0;

SELECT COUNT(*) AS federal_count
FROM tax_authorities
WHERE tax_authority_type = 'federal';

SELECT tax_authority_name
FROM tax_authorities
WHERE tax_authority_type = 'federal';

external_knowledge:
- Dividend events represent the process of a company distributing a portion of its earnings to its shareholders.; 
- Tax implications and compliance status are crucial for companies to ensure they meet regulatory requirements.; 
- Access logs are essential for auditing and security purposes, providing a record of who accessed the dividend event information and when.

sql:
SELECT COUNT(*) AS total_tax_records
FROM tax_implications
WHERE tax_year = 2021;

SELECT COUNT(*) AS total_approved_events_2021
FROM dividend_approvals
WHERE approval_date LIKE '2021-%';

SELECT tax_authority_name, COUNT(*) 
FROM tax_authorities 
GROUP BY tax_authority_name;

SELECT status, COUNT(*) AS event_count
FROM dividend_events
GROUP BY status;
